ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
(vars.userTokenCache default {}) ++ {
	(vars.userId): {
		"accessToken": payload.accessToken,
		"refreshToken": payload.refreshToken default null,
		"expiresAt": payload.expiresAt default null,
		"tokenType": payload.tokenType default "Bearer",
		"storedAt": now()
	}
}

%dw 2.0
output application/java
---
(vars.userDataCache default {}) ++ {
	(vars.userId): {
		"userId": vars.userId,
		"bankName": payload.bankName default "BMO",
		"accountInfo": payload.accountInfo default {},
		"connectedAt": now(),
		"lastAccess": now()
	}
}

%dw 2.0
output application/java
---
(vars.userScopesCache default {}) ++ {
	(vars.userId): {
		"requestedScopes": vars.requestedScopes,
		"grantedScopes": payload.grantedScopes default vars.requestedScopes,
		"scopeUpdatedAt": now()
	}
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
var userDataCache = vars.userDataCache default {}
var userScopesCache = vars.userScopesCache default {}
var users = keysOf(userDataCache) map {
	userId: $,
	hasScopes: userScopesCache[$] != null,
	connectedAt: userDataCache[$].connectedAt,
	bankName: userDataCache[$].bankName
}
---
{
	"status": "success",
	"message": "Retrieved connected users successfully",
	"connectedUsers": users,
	"totalCount": sizeOf(users),
	"timestamp": now()
}
